+    tier: TierKind,
+    embedder_id: &str,
+    db_fingerprint: &str,
+) -> PathBuf {
+    let fingerprint_hash = crc32fast::hash(db_fingerprint.as_bytes());
+    data_dir.join(VECTOR_INDEX_DIR).join(format!(
+        ".staging-{}-{}-{fingerprint_hash:08x}.fsvi",
+        tier.as_str(),
+        safe_path_component(embedder_id)
+    ))
+}
